@page "/privacy"
@attribute [Microsoft.AspNetCore.Components.RenderModeAttribute(typeof(NoInteractiveRenderMode))]
@inject IHttpContextAccessor HttpContextAccessor

<PageTitle>Privacy Policy</PageTitle>

<h1>Privacy Policy</h1>

<p>Your privacy is important to us. This page describes how we handle your data.</p>

@if (_hasConsent)
{
    <div class="alert alert-success">
        ✅ You have already accepted our cookie policy.
    </div>
}
else
{
    <div class="alert alert-warning">
        ⚠️ You have not yet accepted our cookie policy.
    </div>
}

@code {
    private bool _hasConsent;

    protected override void OnInitialized()
    {
        var httpContext = HttpContextAccessor.HttpContext;
        if (httpContext is not null)
        {
            _hasConsent = httpContext.Request.Cookies.ContainsKey("consent");
        }
    }
}

using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Web;

/// <summary>
/// A marker render mode indicating that a page should remain in static SSR
/// and not use any interactive render mode.
/// </summary>
public sealed class NoInteractiveRenderMode : IComponentRenderMode;

/// <summary>
/// Attribute to apply <see cref="NoInteractiveRenderMode"/> to a page component.
/// </summary>
[AttributeUsage(AttributeTargets.Class)]
public sealed class RenderModeAttribute : Attribute
{
    public IComponentRenderMode Mode { get; }

    public RenderModeAttribute(Type renderModeType)
    {
        Mode = (IComponentRenderMode)Activator.CreateInstance(renderModeType)!;
    }
}

